/// <summary>
/// The class <c>ETG_PurchAgreementForm_Extension</c> is used to handle the COC methods related to <c>PurchAgreement</c> form.
/// </summary>
[ExtensionOf(formstr(PurchAgreement))]
final class ETG_PurchAgreementForm_Extension
{

}

Method.Source:
/// <summary>
/// Initializes the Purchase Agreement form.
/// </summary>
public void init()
{
    next Init();

    FormRealControl netWeightMTSControl;
    FormRealControl grossWeightMTSControl;

    if(ETGACFParameters::find().EnablePurchaseAgreementWF)
    {
        FormRun formRunLoc = this;
        formRunLoc.design().workflowType(workflowTypeStr(ETGPurchAgreementType));
    }

    //NS, DLT, actiavte WF control, 09-july-25
    if(!hasActiveWorkflow && ETGACFParameters::find().EnablePurchaseAgreementWF)
    {
        hasActiveWorkflow = WorkflowTable::findActiveTemplate(workFlowTypeStr(ETGPurchAgreementType)).RecId;
    }
    //NE, DLT, actiavte WF control, 09-july-25

    // added code by Ravi to restrict ACF trading details - 26/08 - Start

    if (curext() == "O001")
    {
        ACFTradingDetails.visible(true);

    }
    else
    {
        ACFTradingDetails.visible(false);

    }
    // added code by Ravi to restrict ACF trading details - 26/08 - End

    // Start: Adjust decimals for NETWEIGHTMTS and GROSSWEIGHTMTS only for O001
    if (curext() == "O001")
    {
        netWeightMTSControl = this.design().controlName("ETG_PurchaseAgreementHeader_NETWEIGHTMTS");

        if (netWeightMTSControl)
        {
            netWeightMTSControl.noOfDecimals(3);
        }

        grossWeightMTSControl = this.design().controlName("ETG_PurchaseAgreementHeader_GROSSWEIGHTMTS");

        if (grossWeightMTSControl)
        {
            grossWeightMTSControl.noOfDecimals(3);
        }
    }
    // End: Adjust decimals

}
